  const [showValidationModal, setShowValidationModal] = useState(false);
  const [verifying, setVerifying] = useState(false);
  const [emailToVerify, setEmailToVerify] = useState('');

  // Verifica se o usuário já tem acesso ou se acabou de comprar
  useEffect(() => {
    // 1. Verifica no storage se já era membro
    const access = localStorage.getItem('patriota_access');
    if (access === 'true') {
      setIsAuthorized(true);
    }

    // 2. Verifica se retornou do checkout com sucesso via URL
    const params = new URLSearchParams(window.location.search);
    if (params.get('status') === 'sucesso' || params.get('checkout') === 'success') {
      handleGrantAccess();
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  const handleGrantAccess = () => {
    localStorage.setItem('patriota_access', 'true');
    setIsAuthorized(true);
    setActiveTab('portal');
    setShowSuccessToast(true);
    setTimeout(() => setShowSuccessToast(false), 5000);
  };

  const handleAuthorize = () => {
    window.location.href = CHECKOUT_URL;
  };

  const handleManualVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (!emailToVerify.includes('@')) return;

    setVerifying(true);
    // Simula uma chamada de API para verificar o pagamento na IronPay
    setTimeout(() => {
      setVerifying(false);
      setShowValidationModal(false);
      handleGrantAccess();
    }, 2500);
  };

  return (
    <div className="min-h-screen flex flex-col relative">
      <Navbar onNavigate={setActiveTab} activeTab={activeTab} />

      {/* Notificação de Sucesso de Compra */}
      {showSuccessToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] animate-bounce">
          <div className="bg-green-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 border-2 border-white">
            <CheckCircle size={20} />
            <span className="font-bold">Acesso VIP Liberado! Bem-vindo, Patriota.</span>
          </div>
        </div>
