              <button 
                onClick={() => setShowValidationModal(false)}
                className="absolute top-4 right-4 text-white/50 hover:text-white"
              >
                <X size={24} />
              </button>
              <h3 className="text-xl font-black uppercase italic">Validar Acesso</h3>
              <p className="text-blue-100 text-sm">Insira o e-mail utilizado na compra.</p>
            </div>
            <div className="p-8">
