import { Lock, Newspaper, Users, ArrowRight, ShieldCheck, CheckCircle, MessageCircle, RefreshCw, X, Shield } from 'lucide-react';

const CHECKOUT_URL = "https://go.ironpayapp.com.br/vwtyajrg8t";
// ATENÇÃO: Substitua pelo seu número real
const WHATSAPP_NUMBER = "5500000000000"; 
const SUPPORT_MESSAGE = encodeURIComponent("Olá! Fiz o pagamento no portal mas preciso de ajuda com meu acesso.");
const SUPPORT_WHATSAPP = `https://wa.me/${WHATSAPP_NUMBER}?text=${SUPPORT_MESSAGE}`;

// CHAVE SECRETA: Você usará isso na URL de redirecionamento da IronPay
const AUTH_TOKEN = "sucesso_patriota_2026";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [isProcessingAccess, setIsProcessingAccess] = useState(false);
