  const [showValidationModal, setShowValidationModal] = useState(false);
  const [verifying, setVerifying] = useState(false);
  const [emailToVerify, setEmailToVerify] = useState('');

  useEffect(() => {
    // 1. Verifica se já tem o carimbo de acesso no navegador
    const access = localStorage.getItem('patriota_access_v2');
    if (access === 'verified') {
      setIsAuthorized(true);
    }

    // 2. Verifica se o usuário acabou de vir da IronPay com a chave secreta
    const params = new URLSearchParams(window.location.search);
    if (params.get('auth') === AUTH_TOKEN) {
      handleInitialRedirection();
    }
  }, []);

  const handleInitialRedirection = () => {
    setIsProcessingAccess(true);
    // Simula uma verificação de segurança de 3 segundos para passar credibilidade
    setTimeout(() => {
      handleGrantAccess();
      setIsProcessingAccess(false);
      // Limpa a URL para o segredo não ficar exposto
      window.history.replaceState({}, document.title, window.location.pathname);
    }, 3500);
  };

  const handleGrantAccess = () => {
    localStorage.setItem('patriota_access_v2', 'verified');
    setIsAuthorized(true);
    setActiveTab('portal');
    setShowSuccessToast(true);
    setTimeout(() => setShowSuccessToast(false), 6000);
  };

  const handleAuthorize = () => {
    window.location.href = CHECKOUT_URL;
  };

  const handleManualVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (!emailToVerify.includes('@')) return;

    setVerifying(true);
    // Verificação manual para caso o redirecionamento falhe
    setTimeout(() => {
      setVerifying(false);
      setShowValidationModal(false);
      handleGrantAccess();
    }, 2500);
  };

  // Tela de Processamento de Segurança (Pós-Pagamento)
  if (isProcessingAccess) {
    return (
      <div className="min-h-screen bg-blue-950 flex flex-col items-center justify-center p-6 text-center">
        <div className="relative mb-8">
          <div className="absolute inset-0 bg-blue-500 blur-3xl opacity-20 animate-pulse"></div>
          <Shield size={80} className="text-yellow-500 animate-bounce relative z-10" />
        </div>
        <h2 className="text-3xl font-black text-white uppercase italic tracking-tighter mb-4">
          Autenticando Pagamento
