        <div className="max-w-xs w-full bg-blue-900/50 rounded-full h-2 mb-6 overflow-hidden">
          <div className="bg-green-500 h-full animate-[progress_3.5s_ease-in-out]"></div>
        </div>
        <p className="text-blue-200 font-medium animate-pulse">
          Verificando sua transação na base da IronPay...
        </p>
      </div>
    );
