  return (
    <div className="min-h-screen flex flex-col relative">
      <Navbar onNavigate={setActiveTab} activeTab={activeTab} />

      {showSuccessToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] animate-in slide-in-from-top duration-500">
          <div className="bg-green-600 text-white px-8 py-4 rounded-2xl shadow-2xl flex items-center gap-4 border-2 border-green-400">
            <div className="bg-white/20 p-2 rounded-full">
              <CheckCircle size={24} />
            </div>
            <div>
              <p className="font-black uppercase text-sm tracking-widest">Acesso Confirmado</p>
              <p className="text-xs text-green-100">Bem-vindo ao círculo fechado de 2026!</p>
            </div>
          </div>
        </div>
      )}

      {showValidationModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-blue-950/95 backdrop-blur-xl">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/10">
            <div className="bg-patriotic-gradient p-8 text-white relative">
              <button 
                onClick={() => setShowValidationModal(false)}
                className="absolute top-6 right-6 p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors"
              >
                <X size={20} />
              </button>
              <div className="flex items-center gap-3 mb-2">
                <ShieldCheck className="text-yellow-400" />
                <h3 className="text-xl font-black uppercase italic">Validar Compra</h3>
              </div>
              <p className="text-blue-100 text-sm">Se o seu acesso não liberou automaticamente, insira seu e-mail abaixo.</p>
