      if (
        inputLower === MASTER_EMAIL.toLowerCase() || 
        inputLower.includes('vip2026')
      ) {
        setShowValidationModal(false);
        finalizeAccess();
      } else {
        setVerificationError('Acesso não encontrado. Verifique seu e-mail da IronPay.');
      }
    }, 1500);
